mapper.select:
SELECT t1.* FROM app_auction t1
            left join app_auction_up t2 on t2.car_id=t1.id
where t1.up_state =1
  and t1.source_type=1

    AND t1.fixed_price =#{fixedPrice}


    AND t1.accident_type=#{accType}


    AND t1.parking_place like concat('%',#{parkingPlace},'%')


    AND t1.brand like concat('%',#{brand},'%')


    AND t1.car_state=7
    and t2.begin_time < now()
    and t2.end_time > now()


    and t2.begin_time > now()


    AND t1.price >= #{priceMin}


    AND t1.price <= #{priceMax}



order by t1.create_time desc


    LIMIT #{page.currentResult},#{page.showCount}

SELECT count(*) FROM app_auction t1 left join app_auction_up t2 on t2.car_id=t1.id where t1.up_state =1 and t1.source_type=1
AND t1.fixed_price =#{fixedPrice}
AND t1.accident_type=#{accType}
AND t1.parking_place like concat('%',#{parkingPlace},'%')
AND t1.brand like concat('%',#{brand},'%')
AND t1.car_state=7 and t2.begin_time < now() and t2.end_time > now()
and t2.begin_time > now()
AND t1.price >= #{priceMin}
AND t1.price <= #{priceMax}

SELECT count(*) FROM app_auction t1 left join app_auction_up t2 on t2.car_id=t1.id where t1.up_state =1 and t1.source_type=2
AND t1.fixed_price =#{fixedPrice}
AND t1.accident_type=#{accType}
AND t1.parking_place like concat('%',#{parkingPlace},'%')
AND t1.brand like concat('%',#{brand},'%')
AND t1.car_state=7 and t2.begin_time < now() and t2.end_time > now()
and t2.begin_time > now()
AND t1.price >= #{priceMin}
AND t1.price <= #{priceMax}

SELECT t1.id carId,t1.brand, t1.product_date as productDate, t1.register_date as registerDate, t1.mileage, t1.luxury_car_price as luxuryCarPrice, t1.first_amount as firstAmount, t1.phone as phoneNumber, CONCAT(CONCAT(LEFT(t1.product_date,4),'年'),' ',CONCAT(t1.mileage,'公里'))label , t1.price FROM app_auction t1 left join app_auction_up t2 on t1.id=t2.car_id WHERE t1.source_type = 2 and t1.car_state=7 and t1.up_state=1 and t2.begin_time < now() and t2.end_time > now()
AND t1.brand like concat('%',#{keyWord},'%')
AND t1.brand like concat('%',#{brand},'%')
AND t1.accident_type = #{accidentType}
AND t1.mileage >= #{startMileage}
AND t1.mileage < #{endMileage}
AND t1.price < #{endPrice}
AND t1.price >= #{startPrice}
AND t1.parking_place like concat('%', #{parkingPlace},'%')
AND to_days(t2.begin_time) = to_days(now())
AND t1.accident_type like concat('%',#{type},'%')
ORDER BY t1.create_time DESC
LIMIT #{page.currentResult},#{page.showCount}
